t = int(input())
for _ in range(t):
    n = int(input())
    a = list(map(int, input().split()))
    b = list(map(int, input().split()))

    result = []
    for i in range(n):
        dominators = [j for j in range(n) if j != i and a[j] > a[i] and b[j] > b[i]]
        can_win = True
        for q in dominators:
            # Need R that beats Q and P beats R
            found = False
            for r in range(n):
                if r != i and r != q:
                    if (a[r] > a[q] or b[r] > b[q]) and (a[i] > a[r] or b[i] > b[r]):
                        found = True
                        break
            if not found:
                can_win = False
                break
        result.append('1' if can_win else '0')
    print(''.join(result))

